//! Spec-compliance tests: Section & Story Edge Cases (ISO 29500-1 §17.6, §17.10)
//!
//! These tests probe edge cases in section/header/footer handling that are
//! specified in ECMA-376 / ISO 29500-1 but may not be correctly implemented.
//! Tests that fail document real spec-compliance gaps.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/section-story-spec/create_fixtures.py`.

use std::fs;

use stemma::{
    BlockNode, CanonDoc, DocxRuntime, ExportMode, HeaderFooterKind, InlineNode, SimpleRuntime,
    TrackedBlock,
};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/section-story-spec";

// -- helpers ----------------------------------------------------------------

/// Extract plain text from tracked blocks.
fn blocks_text(blocks: &[TrackedBlock]) -> String {
    let mut text = String::new();
    for tb in blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

/// Collect all mid-document section properties (from pPr/sectPr).
fn section_paragraphs(doc: &CanonDoc) -> Vec<&stemma::SectionProperties> {
    let mut props = Vec::new();
    collect_section_props_tracked(&doc.blocks, &mut props);
    props
}

fn collect_section_props_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_section_props_bare<'a>(
    blocks: &'a [BlockNode],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

// ==========================================================================
// Test 1: titlePg=true with no first-page header — blank header synthesis
// ==========================================================================

/// ISO 29500-1 §17.10.5: "If no headerReference for the first page header is
/// specified and the titlePg element is specified, then the first page header
/// shall be inherited from the previous section or, if this is the first
/// section in the document, a new blank header shall be created."
///
/// Fixture: single section with titlePg=true and only a default header.
/// No first-page header reference is defined.
///
/// Expected: The model should have a First-kind header ref on the body
/// section (either inherited or synthesized as blank), because titlePg=true
/// means the first page needs its own header.
#[test]
fn spec_titlepg_true_no_first_header_synthesizes_blank() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "titlepg-true-no-first-header");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");

    // titlePg should be parsed as true
    assert_eq!(
        body_sp.title_page,
        Some(true),
        "title_page should be Some(true), got {:?}",
        body_sp.title_page
    );

    // Must have a Default header ref (the one explicitly declared)
    let default_ref = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default);
    assert!(
        default_ref.is_some(),
        "should have a Default header ref, got refs: {:?}",
        body_sp.header_refs
    );

    // Per §17.10.5: first section with titlePg=true but no first-page header
    // must get a blank first-page header. The model should have a First-kind ref.
    let first_ref = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First);
    assert!(
        first_ref.is_some(),
        "ISO 29500-1 §17.10.5: section with titlePg=true but no first-page header \
         reference should get a synthesized blank First-kind header ref. \
         Got header_refs: {:?}",
        body_sp.header_refs
    );

    // The First-kind header story should exist in doc.headers
    if let Some(fref) = first_ref {
        let story = doc.headers.iter().find(|h| h.part_name == fref.part_path);
        assert!(
            story.is_some(),
            "synthesized First-kind header story must exist in doc.headers"
        );
    }
}

// ==========================================================================
// Test 2: Continuous section without pgSz inherits page dimensions
// ==========================================================================

/// ISO 29500-1 §17.6.22: Continuous section breaks "might not specify certain
/// page-level section properties, since they shall be inherited."
///
/// Fixture: Section 1 has pgSz w=12240 h=15840. Section 2 is continuous
/// with NO pgSz element (but explicit pgMar).
///
/// Expected: Section 2 inherits page_width=12240 and page_height=15840
/// from Section 1 via `propagate_continuous_section_properties()`.
#[test]
fn spec_continuous_section_inherits_page_size() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "continuous-no-page-size");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );

    // Section 1: explicit page size
    let s1 = section_props[0];
    assert_eq!(
        s1.page_width,
        Some(12240),
        "S1 page_width should be 12240, got {:?}",
        s1.page_width
    );
    assert_eq!(
        s1.page_height,
        Some(15840),
        "S1 page_height should be 15840, got {:?}",
        s1.page_height
    );

    // Section 2 (body-level): continuous, no pgSz
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "Section 2 should be continuous, got {:?}",
        body_sp.section_type
    );

    // Section 2 should inherit page dimensions from Section 1
    assert_eq!(
        body_sp.page_width,
        Some(12240),
        "ISO 29500-1 §17.6.22: continuous section without pgSz should inherit \
         page_width=12240 from Section 1, got {:?}",
        body_sp.page_width
    );
    assert_eq!(
        body_sp.page_height,
        Some(15840),
        "ISO 29500-1 §17.6.22: continuous section without pgSz should inherit \
         page_height=15840 from Section 1, got {:?}",
        body_sp.page_height
    );

    // Section 2's explicit margins should be preserved (not overwritten)
    assert_eq!(
        body_sp.margin_top,
        Some(720),
        "Section 2 has explicit margin_top=720, should not be overwritten, got {:?}",
        body_sp.margin_top
    );
}

// ==========================================================================
// Test 3: Even-page header inheritance with evenAndOddHeaders enabled
// ==========================================================================

/// ISO 29500-1 §17.10.5: "If no headerReference for the even page header is
/// specified and the evenAndOddHeaders element is specified, then the even page
/// header shall be inherited from the previous section."
///
/// Fixture: evenAndOddHeaders=true in settings.xml. Section 1 has default +
/// even headers. Section 2 has only a default header (no even ref).
///
/// Expected: Section 2 should inherit the even header from Section 1.
#[test]
fn spec_even_header_inheritance_with_even_odd_enabled() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "even-header-inheritance");

    // Should have 3 header stories: S1 default, S1 even, S2 default
    assert_eq!(
        doc.headers.len(),
        3,
        "should have 3 header stories (S1 default, S1 even, S2 default), got {}",
        doc.headers.len()
    );

    // Verify Even-kind header exists (should not be filtered since evenAndOddHeaders=true)
    let even_stories: Vec<_> = doc
        .headers
        .iter()
        .filter(|h| h.kind == HeaderFooterKind::Even)
        .collect();
    assert_eq!(
        even_stories.len(),
        1,
        "should have exactly 1 Even-kind header story, got {}",
        even_stories.len()
    );
    let even_text = blocks_text(&even_stories[0].blocks);
    assert!(
        even_text.contains("S1 Even Header"),
        "Even header should contain 'S1 Even Header', got: '{}'",
        even_text
    );

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );

    // Section 1: should have default + even refs
    let s1 = section_props[0];
    let s1_even = s1
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Even);
    assert!(
        s1_even.is_some(),
        "S1 should have an Even-kind header ref, got refs: {:?}",
        s1.header_refs
    );

    // Section 2 (body-level): should inherit even header from S1
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");

    let s2_even = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Even);
    assert!(
        s2_even.is_some(),
        "ISO 29500-1 §17.10.5: S2 should inherit Even-kind header ref from S1, \
         got header_refs: {:?}",
        body_sp.header_refs
    );

    // The inherited even ref should point to the same story as S1's even ref
    if let (Some(s1e), Some(s2e)) = (s1_even, s2_even) {
        assert_eq!(
            s1e.part_path, s2e.part_path,
            "S2's inherited Even header should point to S1's Even header. \
             S1 even part_path={}, S2 even part_path={}",
            s1e.part_path, s2e.part_path
        );
    }

    // Section 2 should have its own default header (different from S1's)
    let s1_default = s1
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .expect("S1 should have a Default ref");
    let s2_default = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .expect("S2 should have a Default ref");
    assert_ne!(
        s1_default.part_path, s2_default.part_path,
        "S2's default header should be its own (different from S1). \
         S1 default part_path={}, S2 default part_path={}",
        s1_default.part_path, s2_default.part_path
    );
}

// ==========================================================================
// Test 4: First-page header inheritance with titlePg across sections
// ==========================================================================

/// ISO 29500-1 §17.10.5: "If no headerReference for the first page header is
/// specified and the titlePg element is specified, then the first page header
/// shall be inherited from the previous section."
///
/// Fixture: S1 has titlePg=true with default + first headers. S2 has
/// titlePg=true with only a default header (no first ref).
///
/// Expected: S2 should inherit the first-page header from S1, so S2 has
/// both default (own) and first (inherited from S1) header refs.
#[test]
fn spec_titlepg_first_header_inherited_from_previous_section() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "titlepg-first-header-inheritance");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );

    // S1: should have default + first header refs
    let s1 = section_props[0];
    assert_eq!(
        s1.title_page,
        Some(true),
        "S1 title_page should be Some(true)"
    );

    let s1_first = s1
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First);
    assert!(
        s1_first.is_some(),
        "S1 should have a First-kind header ref, got: {:?}",
        s1.header_refs
    );

    let s1_default = s1
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default);
    assert!(
        s1_default.is_some(),
        "S1 should have a Default header ref, got: {:?}",
        s1.header_refs
    );

    // S2 (body-level): titlePg=true, only default header declared
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");

    assert_eq!(
        body_sp.title_page,
        Some(true),
        "S2 title_page should be Some(true)"
    );

    // S2 should have its own default header
    let s2_default = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default);
    assert!(
        s2_default.is_some(),
        "S2 should have a Default header ref, got: {:?}",
        body_sp.header_refs
    );

    // Per §17.10.5: S2 has titlePg=true but no first-page header ref declared.
    // It should inherit the first-page header from S1.
    let s2_first = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First);
    assert!(
        s2_first.is_some(),
        "ISO 29500-1 §17.10.5: S2 with titlePg=true but no first-page header ref \
         should inherit First-kind header from S1. Got header_refs: {:?}",
        body_sp.header_refs
    );

    // The inherited first ref should point to S1's first header
    if let (Some(s1f), Some(s2f)) = (s1_first, s2_first) {
        assert_eq!(
            s1f.part_path, s2f.part_path,
            "S2's inherited First header should point to S1's First header. \
             S1 first part_path={}, S2 first part_path={}",
            s1f.part_path, s2f.part_path
        );

        // Verify the inherited story has the right content
        let story = doc
            .headers
            .iter()
            .find(|h| h.part_name == s2f.part_path)
            .expect("should find the inherited First header story");
        let text = blocks_text(&story.blocks);
        assert!(
            text.contains("S1 First Header"),
            "S2's inherited first header should contain 'S1 First Header', got: '{}'",
            text
        );
    }
}

// ==========================================================================
// Test 5: nextColumn section type roundtrips through export
// ==========================================================================

/// ECMA-376 §17.6.22 (ST_SectionMark): nextColumn is a valid section break
/// type that starts the next section in the next column.
///
/// This test verifies that the nextColumn section type survives an
/// import -> export -> re-import roundtrip.
#[test]
fn spec_next_column_roundtrip() {
    let path = format!("{FIXTURES}/next-column-roundtrip/input.docx");
    let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));

    let runtime = SimpleRuntime::new();
    let import = runtime.import_docx(&bytes).expect("import");

    // Verify import: section type should be NextColumn
    let view = runtime.view(&import.doc_handle).expect("view");
    let section_props = section_paragraphs(&view.canonical);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );
    assert_eq!(
        section_props[0].section_type,
        Some(stemma::domain::SectionType::NextColumn),
        "imported section_type should be NextColumn"
    );

    // Export
    let exported = runtime
        .export_docx(&import.doc_handle, ExportMode::Redline)
        .expect("export should succeed");
    assert!(!exported.is_empty(), "exported DOCX must not be empty");

    // Re-import and verify nextColumn survived
    let verify_runtime = SimpleRuntime::new();
    let reimport = verify_runtime
        .import_docx(&exported)
        .expect("re-import should succeed");
    let view2 = verify_runtime.view(&reimport.doc_handle).expect("view");
    let section_props2 = section_paragraphs(&view2.canonical);
    assert!(
        !section_props2.is_empty(),
        "re-imported doc should have at least one mid-document section"
    );
    assert_eq!(
        section_props2[0].section_type,
        Some(stemma::domain::SectionType::NextColumn),
        "ECMA-376 §17.6.22: nextColumn section type should survive roundtrip, \
         got {:?}",
        section_props2[0].section_type
    );
}
